import _ from 'lodash'
import path from 'path'
import { defineConfig, loadEnv, ConfigEnv, UserConfigExport } from 'vite'
import { viteMockServe } from 'vite-plugin-mock'
import react from '@vitejs/plugin-react-swc'
import svgr from 'vite-plugin-svgr'

// env variables to be excluded in production build
const envExcludes = [
  'VITE_SERVE_PORT',
  'VITE_API_PROXY_TARGET',
  'VITE_RSA_PRIVATE_KEY',
]

// https://vitejs.dev/config/
export default ({ command, mode }: ConfigEnv): UserConfigExport => {
  // 根据 mode 配置加载不同的 .env[mode] 文件
  const configEnv = loadEnv(mode, './env')
  const serverProxy = require('./server/proxy.cjs')
  const appThemeName = configEnv.VITE_APP_NAMESPACE.toLowerCase()
  const appHeaderHeight = configEnv.VITE_APP_HEADER_HEIGHT || 56

  // 配置 Vite 依赖预编译，缩短项目冷启动时间
  const optimizeDeps = {
    include: ['react', 'react-dom', 'react-router-dom'],
  }

  return defineConfig({
    envDir: './env',
    envPrefix:
      configEnv.VITE_USER_NODE_ENV === 'production'
        ? Object.keys(_.omit(configEnv, envExcludes))
        : undefined,
    plugins: [
      react(),

      svgr({
        svgrOptions: {
          icon: true,
        },
      }),

      // https://github.com/vbenjs/vite-plugin-mock/blob/main/README.zh_CN.md
      viteMockServe({
        // mock 文件夹
        mockPath: 'mock',
        // 是否开启mock
        enable: configEnv.VITE_USE_MOCK === 'true',
      }),
    ],
    resolve: {
      alias: {
        '@': path.resolve(__dirname, './src'),
        '@common': path.resolve(__dirname, './packages/common/src'),
      },
    },
    css: {
      preprocessorOptions: {
        less: {
          modifyVars: {
            hack: `true; @header-height: ${appHeaderHeight}px; @import (reference) "${path.resolve(__dirname, `./packages/common/src/assets/styles/variables.${appThemeName}.less`)}";`,
          },
          // 支持内联 JavaScript
          javascriptEnabled: true,
        },
      },
    },

    server: {
      // 项目启动是否打开页面
      open: true,
      port: +configEnv.VITE_SERVE_PORT,
      host: '0.0.0.0',
      proxy: serverProxy(configEnv),
    },
    optimizeDeps,
    build: {
      // 项目打包路径
      outDir: configEnv.VITE_APP_OUT_DIR,
      // 打包后是否生成 source map 文件
      sourcemap: false,
      // minify: 'esbuild', // 是否进行压缩,boolean | 'terser' | 'esbuild',默认使用esbuild
      // terserOptions: {},
      // 设置为 false 来禁用将构建后的文件写入磁盘
      write: true,
      // 默认情况下，若 outDir 在 root 目录下，则 Vite 会在构建时清空该目录。
      emptyOutDir: true,
      // 限制最大包的大小
      chunkSizeWarningLimit: 2000,
      cssCodeSplit: true, //css 拆分
      rollupOptions: {
        output: {
          chunkFileNames: 'assets/js/[name]-[hash].js',
          entryFileNames: 'assets/js/[name]-[hash].js',
          assetFileNames: 'assets/static/[name]-[hash].[ext]',

          manualChunks: {
            // 1. 将 React 相关库打包成单独的 chunk 中
            'react-vendor': [
              'react',
              'react-dom',
              'react-router-dom',
              '@reduxjs/toolkit',
              'redux-first-history',
              'redux-logger',
              'i18next',
              'react-i18next',
            ],
            // 2. @arco-design 依赖
            '@arco-design-vendor': ['@arco-design/web-react'],
            // 3. 其他第三方依赖库
            library: ['lodash', 'axios', 'ahooks', 'classnames', 'crypto-js'],
          },
        },
      },
    },
  })
}

