import { defineConfig } from "vite";
import path from "path";
import react from "@vitejs/plugin-react";

//插件
import svgr from 'vite-plugin-svgr' // SVG作为组件
import AutoImport from 'unplugin-auto-import/vite' // 自动导入
// import {visualizer} from 'rollup-plugin-visualizer' // 包分析
import compression from 'vite-plugin-compression' // gzip压缩

// https://vitejs.dev/config/
export default defineConfig({
  plugins: [
    react(),
    svgr(),
    AutoImport({
      imports: ["react"],
      dts: "src/auto-imports.d.ts", // 生成 `auto-imports.d.ts` 文件
    }),
    // visualizer(),
    compression({
      algorithm: "gzip",
      threshold: 10240, // 只有大小大于10kb的文件才会被压缩
      ext: ".gz", // 压缩后的文件后缀
    }),
  ],
  resolve: {
    extensions: [".ts", ".tsx", ".js", ".jsx", ".json"],
    alias: {
      "@": path.resolve(__dirname, "src"),
      "@components": path.resolve(__dirname, "src/components"),
    },
  },
  // 生产环境特定配置
  build: {
    outDir: "dist", // 打包输出目录
    assetsDir: "assets", // 静态资源目录
    sourcemap: false, // 生产环境不建议开启 sourcemap
    minify: "terser", // 使用 terser 进行代码压缩
    terserOptions: {
      compress: {
        drop_console: true, // 移除 console.log
        drop_debugger: true, // 移除 debugger
      },
    },
    rollupOptions: {
      output: {
        // 代码分割配置
        manualChunks(id) {
          if (id.includes("node_modules")) {
            return id
              .toString()
              .split("node_modules/")[1]
              .split("/")[0]
              .toString();
          }
        },
        // 文件名哈希
        chunkFileNames: "assets/js/[name]-[hash].js",
        entryFileNames: "assets/js/[name]-[hash].js",
        assetFileNames: "assets/[ext]/[name]-[hash].[ext]",
      },
    },
    //资源文件处理
    assetsInlineLimit: 4096, //4kb以下内联
  },
  css: {
    modules: {
      localsConvention: "camelCase", //css模块化命名转换
    },
    preprocessorOptions: {
      less: {
        additionalData: `@import "@/styles/gloable.less";`, //全局less变量
      },
    },
  },
  // 基础公共路径
  base: "./",
  // 开发服务器配置
  server: {
    port: 5173,
    open: true,
    // proxy: {
    //   "/api": {
    //     target: "http://localhost:3000",
    //     changeOrigin: true,
    //     rewrite: (path) => path.replace(/^\/api/, ""),
    //   },
    // }
  },
  // 预览配置
  preview: {
    port: 4173,
    open: true,
  },
});

