import react from '@vitejs/plugin-react-swc';
import postcssPxtorem from 'postcss-pxtorem';
// https://vitejs.dev/config/
export default defineConfig({
  base: '/',
  plugins: [react()],
  css: {
    postcss: {
      plugins: [
        postcssPxtorem({
          rootValue: 12,
          unitPrecision: 5,
          propList: ['*'],
          exclude: /PX$/,
          minPixelValue: 0,
          selectorBlackList: []
        })
      ]
    }
  },
  server: {
    port: 3000,
    strictPort: true,
    // hmr: {
    //    // clientPort: 3000,
